    internal class SceneTrackerCompletionPresetInjector : ICompletionPresetInjector
    {
        internal static ChatCompletionPresetsDbModel InjectPreset()
        {
            return new ChatCompletionPresetsDbModel
                {
                    Name = "Default-Scene-Tracker-Preset",
                    ChatCompletionPresetId = StorageConstants.DEFAULT_SCENE_TRACKER_COMPLETION_PRESET,
                    CreatedAtUtc = DateTime.UtcNow,
                    Format = new GlobalPromptContextFormat()
                    {
                        MaxTokensToGenerate = 4096,
                        OrderedElementsWithinTheGlobalPromptContext = new List<PromptContextFormatElement>
                        {
                            new PromptContextFormatElement
                            {
                                Tag = PromptContextFormatTag.Directive,
                                Name = "Directive",
                                Enabled = true,
                                Options = new PromptContextFormatElementOptions
                                {
                                    Format = "<task>\r\nStop the roleplay. You are a novels and roleplay analyst, tasked with providing clear, consistent, structured and cohesive updates to a scene tracker for a roleplay session in a fictional story. Use the latest messages, previous scene tracker details, and context from recent messages to accurately analyze the story and update the scene tracker. Your response must ensure that each field is filled, complete, immersive and coherent with the last scene tracker details as well what exactly happens in the scene. Include only the specified fields. When specific information is missing from the story context, make reasonable assumptions based on prior descriptions, logical inferences, or character details. Keep the description CONSISTENT with the description from the last_scene_tracker tag as well as what changed from that description, which is provided in the messages_after_last_scene_tracker tag. To keep your reply reasonable in size, limit your tracking to the four most important characters in a scene.\r\n\r\n<format>\r\n{\r\n  \"mainThemes\" : value,\r\n  \"nestedThemes\": value,\r\n  \"currentDateTime\": value,\r\n  \"location\": value,\r\n  \"allCharactersActiveInScene\": value,\r\n  \"charactersAnalysis\": [\r\n    {\r\n      \"name\": value,\r\n      \"mood\": value,\r\n      \"facialExpression\": value,\r\n      \"outfit\": value,\r\n      \"underwear\": value,\r\n      \"stateOfDress\": value,\r\n      \"exposedBodyParts\": value,\r\n      \"clothingStateOfDress\": value,\r\n      \"hairStyle\": value,\r\n      \"posture\": value,\r\n      \"semenOnBodyLocation\": value,\r\n      \"bodyPosition\": value,\r\n      \"personalGainInScene\": value,\r\n      \"relevantKinksInScene\": value,\r\n      \"relevantSecretKinksInScene\": value,\r\n      \"relevantPersonalityTraits\": value,\r\n      \"innerThoughtsOrMonologue\": value,\r\n      \"nextActionsAccordingToPersonality\": [\r\n        value1,\r\n        value2,\r\n        value3\r\n      ]\r\n    }\r\n  ],\r\n  \"playerAnalysis\": {\r\n    \"eyesDirection\": {\r\n      \"lookingAtCharacter\": \"Character name or leave null when player isn't looking at someone.\",\r\n      \"bodyPartBeingLookedAt\": \"The body part if looking at a character\"\r\n    },\r\n    \"name\": value,\r\n    \"mood\": value,\r\n    \"facialExpression\": value,\r\n    \"outfit\": value,\r\n    \"underwear\": value,\r\n    \"stateOfDress\": value,\r\n    \"exposedBodyParts\": value,\r\n    \"clothingStateOfDress\": value,\r\n    \"hairStyle\": value,\r\n    \"posture\": value,\r\n    \"semenOnBodyLocation\": value,\r\n    \"bodyPosition\": value,\r\n    \"nextActionsAccordingToPersonality\": [\r\n      value1,\r\n      value2,\r\n      value3\r\n    ]\r\n  }\r\n}\r\n</format>\r\n\r\n<fieldsDescription>\r\n  \"mainThemes\": Categorize the scene in one to three strong thematic or topic keywords relevant to the scene to help trigger contextual information. (e.g., 'Romance' or 'Action,Combat')\r\n  \"nestedThemes\": Categorize the scene in one to five keywords that gives more details on the main themes/topics. (e.g., when mainCategories includes 'Romance', you may add 'Sex,Penetration,Semen' for example, if the scene include those themes).\r\n  \"currentDateTime\": Represents the current date and time in the current scene within the story. Adjust time in small increments, ideally only a few seconds per update, to reflect realistic scene progression (infer the time required to do the actions represented in the messages_after_last_scene_tracker actions and add it. Avoid large jumps unless a significant time skip (e.g., sleep, travel) is explicitly stated. Format this field as \"Day Month Year HH:MM:SS\", for example '3 March 1974 13:25:30'.\r\n  \"location\": The current location of the scene within the world. Avoid unintended reuse of specific locations from previous examples or responses. Provide specific, relevant, and detailed locations based on the context, using the format: \"preciseLocation, generalLocation, buildingOrApproximativeLocation, regionalLocation, countryOrInWorldLocation\". For example, \"Food court, second floor near east wing entrance, Madison Square Mall, Los Angeles, CA\" or \"Great hall, first floor near great staircase, Hogwarts, Scotland, Great Britain\" would be good descriptions.\r\n  \"allCharactersActiveInScene\": Array of all the characters that are active in the scene (talking, listening, thinking, physically close to {{user}}, interacting with another character, etc). List only their names. Avoid including the player ({{user}}). Make sure to include any characters that followed {{user}} or are in proximity to {{user}} or that could interact with {{user}}. \r\n  \"charactersAnalysis\": characters other than {{user}} in the scene.\r\n  \"playerAnalysis\": {{user}} analysis.\r\n  \"name\": The name of the character.\r\n  \"mood\": In what mood is the character. Analyze the character personality and make reasonable assumption on how they would feel in the current scene. Limit this description to keywords and to at most 30 words.\r\n  \"facialExpression\": Keyword for SDXL image generation. Limit your description to ONE of these choices: 'Neutral,Admiration,Amusement,Anger,Annoyance,Arousal,Arrogant,Bored,Confusion,Crying,Curiosity,Disappointment,Disapproval,Disgust,Embarrassment,Excitement,Fear,Gratitude,Grief,Jealousy,Joy,Laughing,Nervousness,Pride,Realization,Relief,Remorse,Sadness,Serious,Shy,Surprised,Sleepy,Worried'. If you're unsure, select 'Neutral'.\r\n  \"outfit\": Describe the complete outfit of this character, using specific details for color, fabric, and style (e.g., “fitted black leather jacket with silver studs on the collar”). Give a very small description (maximum 30 tokens).\r\n  \"underwear\": Describe the character's underwear (underneath clothes or visible). If underwear is intentionally missing, specify this clearly in the description (e.g., \"No bra\", \"No panties\" for female or \"no underwear\" for male).\r\n  \"stateOfDress\": Describe how put-together or disheveled the character appears, including any removed clothing. If the character is undressed, indicate where discarded items are placed.\r\n  \"exposedBodyParts\": Describe which parts of their body is exposed to the eyes of others. Choose between 'Face,Neck,Hands,Feet,Legs,Thighs,Genitals,Stomach,Breasts'.\r\n  \"clothingStateOfDress\": How dressed is the character? You must choose between ONE of these choices: 'Unknown,Naked,Underwear,Clothed'. If unsure, select 'Unknown'. You may infer the character state of dress from the context and the actions taken by the characters.\r\n  \"hairStyle\": Describe the character's hairstyle (e.g., \"straight long hair\"). Give a very small description (one to five words).\r\n  \"posture\": Describe the character's posture (e.g., \"kneeling beside the cat\", \"running away\", \"leaning forward\"). Keep your description very lean (maximum 20 tokens).\r\n  \"semenOnBodyLocation\": When the current scene is erotica, after a male climax, this field determine where he came (where is semen is on his partner's body). This information is absolutely capital for the story. Select a choice between 'None,Unknown,OnFace,OnBreasts,OnStomach,OnThighsOrPelvis,InVagina,OnFeet'. When unsure, select 'Unknown'.\r\n  \"bodyPosition\": In what position is this character body currently? Choose an option from the following choices: 'Standing,Sitting,Walking,Running,Kneeling,Fighting,OnBack,OnStomach,OnAllFours,Unknown'. When unsure, select 'Unknown'. When the body position isn't available in the list, select the closest one.\r\n  \"personalGainInScene\": The TWO most relevant gains or goals of this character that is in play in the current scene. Limit your desciption to 25 tokens.\r\n  \"relevantKinksInScene\": The five most relevant kinks of this character in the current scene in the following format: \"Kink name 1, kink name 2\", etc. e.g.: \"Domination, Marking, Bondage.\".\r\n  \"relevantSecretKinksInScene\": The five most relevant secret kinks of this character in the current scene in the following format: \"Kink name 1, kink name 2\", etc. e.g.: \"Domination, Marking, Bondage.\".\r\n  \"relevantPersonalityTraits\": The three most relevant personality traits of this character in the current scene.\r\n  \"innerThoughtsOrMonologue\": Infer a reasonable inner monologue or inner thoughts for this character following the current scene. Limit your description to fifty words.\r\n  \"nextActionsAccordingToPersonality\": Infer reasonable, but imaginative actions that this character could take next. Back your suggestions based on their personality, mood and personal gains from the current scene. Limit your description to three actions. Each actions must be at most 10 keywords long. Include one option that would be the most logical according to the character personality and mood, another that would focus on personal gain/goal and a final one that would create something unexpected whilst being logical according to this character personality.\r\n  \r\n  \"lookingAtCharacter\": When the player is looking at a character, name this character here. Otherwise, leave it null or empty.\r\n  \"bodyPartBeingLookedAt\": When the player is looking at a character, select the body part that is being looked at here. Choose between the following choices: 'Face,UpperBody,Feet,Ass,GeneralDirection,Unknown,Default'. Select 'Unknown' if you are unsure or if it's not applicable.\r\n</fieldsDescription>\r\n\r\n<key_instructions>\r\n- Use only details provided or logically inferred from context. Do not introduce speculative or unnecessary information.\r\n- Treat each scene update as a standalone, complete entry. Respond with the full tracker every time, even if there are only minor updates.\r\n</key_instructions>\r\n\r\n<examplesGoodReplies>\r\n```json\r\n{\r\n  \"mainThemes\": \"Social,Friendship,Deception\",\r\n  \"nestedThemes\": \"Aftermath Concealment,Time Pressure\",\r\n  \"currentDateTime\": \"4 October 1995 11:53:00\",\r\n  \"location\": \"Great Hall, first floor near Slytherin table, Hogwarts Castle, Scottish Highlands, Great Britain\",\r\n  \"allCharactersActiveInScene\": [\r\n    \"Daphne Greengrass\",\r\n  \"Tracey Davis\",\r\n  \"Pansy Parkinson\",\r\n  \"Marie\",\r\n  \"Laurent\"\r\n  ],\r\n  \"charactersAnalysis\": [\r\n    {\r\n      \"name\": \"Daphne Greengrass\",\r\n      \"mood\": \"Patient, slightly concerned, observant\",\r\n      \"facialExpression\": \"Neutral\",\r\n      \"outfit\": \"Elegant slytherin robes, silver serpent brooch at collar, white blouse\",\r\n      \"underwear\": \"Pale blue lace bra and matching panties\",\r\n      \"stateOfDress\": \"Completely put-together, not a wrinkle visible\",\r\n      \"exposedBodyParts\": \"Face, Hands\",\r\n      \"clothingStateOfDress\": \"Clothed\",\r\n      \"hairStyle\": \"Platinum blonde, long and straight, pinned back elegantly\",\r\n      \"posture\": \"Sitting upright at Slytherin table, glancing toward entrance periodically\",\r\n      \"semenOnBodyLocation\": \"None\",\r\n      \"bodyPosition\": \"Sitting\",\r\n      \"personalGainInScene\": \"Show her composure and her control. Acting dignified to enhance her carefully constructed image.\",\r\n      \"relevantKinksInScene\": \"None\",\r\n      \"relevantSecretKinksInScene\": \"None\",\r\n      \"relevantPersonalityTraits\": \"Observant, Careful, Intelligent\",\r\n      \"innerThoughtsOrMonologue\": \"Eleanor is finally here. Tracey fidgets when worried. Eleanor is never this late without reason. Something must've happened. I should not pry, but I need to know more.\",\r\n      \"nextActionsAccordingToPersonality\": [\r\n        \"Greet Eleanor with measured warmth\",\r\n        \"Exchange glance with Tracey to gauge her reaction\",\r\n        \"Inquire subtly about delay\"\r\n      ]\r\n    },\r\n    {\r\n      \"name\": \"Tracey Davis\",\r\n      \"mood\": \"Anxious, relieved, affectionate\",\r\n      \"facialExpression\": \"Relief\",\r\n      \"outfit\": \"Slytherin robes with silver clasp, soft cashmere sweater beneath, charcoal skirt\",\r\n      \"underwear\": \"Cream lace bra and matching panties\",\r\n      \"stateOfDress\": \"Neat but slightly rumpled from waiting, collar touched nervously\",\r\n      \"exposedBodyParts\": \"Face, Hands\",\r\n      \"clothingStateOfDress\": \"Clothed\",\r\n      \"hairStyle\": \"Dark brown chin-length, tucked behind ears with stray strands\",\r\n      \"posture\": \"Leaning forward at table, fingers touching collarbone, perking up as Eleanor enters\",\r\n      \"semenOnBodyLocation\": \"None\",\r\n      \"bodyPosition\": \"Sitting\",\r\n      \"personalGainInScene\": \"Showing Eleanor her concern to show how much she care to enhance their friendship.\",\r\n      \"relevantKinksInScene\": \"None\",\r\n      \"relevantSecretKinksInScene\": \"None\",\r\n      \"relevantPersonalityTraits\": \"Observant, Loyal, Caring\",\r\n      \"innerThoughtsOrMonologue\": \"She's finally here and she's safe. I worried for nothing. Although her cheeks are flushed, I wonder why. I will ask simple questions to poke around.\",\r\n      \"nextActionsAccordingToPersonality\": [\r\n        \"Smile warmly at Eleanor's approach\",\r\n        \"Slide closer to Daphne to make room\",\r\n        \"Offer to fetch pumpkin juice\"\r\n      ]\r\n    },\r\n    {\r\n      \"name\": \"Pansy Parkinson\",\r\n      \"mood\": \"Shattered, vengeful, masking desperately\",\r\n      \"facialExpression\": \"Serious\",\r\n      \"outfit\": \"Freshly reapplied makeup, repaired robes, borrowed or spare knickers beneath\",\r\n      \"underwear\": \"Spare black lace thong, less expensive than usual, hastily donned\",\r\n      \"stateOfDress\": \"Artfully reconstructed, every hair in place, perfume heavy to mask scent\",\r\n      \"exposedBodyParts\": \"Face, Hands\",\r\n      \"clothingStateOfDress\": \"Clothed\",\r\n      \"hairStyle\": \"Brown chin-length bob, aggressively smoothed, sprayed into submission\",\r\n      \"posture\": \"Rigid posture at distant table, shoulders squared, jaw tight\",\r\n      \"semenOnBodyLocation\": \"None\",\r\n      \"bodyPosition\": \"Sitting\",\r\n      \"personalGainInScene\": \"Showing Eleanor that she is more gracious than her by keeping her emotions under control.\",\r\n      \"relevantKinksInScene\": \"Aesthetic Perfectionism, Information as Currency\",\r\n      \"relevantSecretKinksInScene\": \"Forced Vulnerability & Emotional Exposure\",\r\n      \"relevantPersonalityTraits\": \"Cunning, Insecure, Judgmental\",\r\n      \"innerThoughtsOrMonologue\": \"Eleanor walks in like nothing happened. Like she didn't just made me cum. I will smile at Draco and act like nothing happened. I will ignore her, no one can know what happened between us.\",\r\n      \"nextActionsAccordingToPersonality\": [\r\n        \"Avoid eye contact with Eleanor entirely\",\r\n        \"Laugh too loudly at Draco's comment\",\r\n        \"Excuse herself to check appearance again\"\r\n      ]\r\n    }\r\n  ],\r\n  \"playerAnalysis\": {\r\n    \"eyesDirection\": {\r\n      \"lookingAtCharacter\": \"Tracey Davis\",\r\n      \"bodyPartBeingLookedAt\": \"Face\"\r\n    },\r\n    \"name\": \"Eleanor Ateres\",\r\n    \"mood\": \"Satisfied, slightly rushed, confident\",\r\n    \"facialExpression\": \"Joy\",\r\n    \"outfit\": \"Fresh white blouse, green tie, green Slytherin jacket, green plaid skirt, fresh black pantyhose, black feminine shoes\",\r\n    \"underwear\": \"Fresh black lace bra, matching black lace thong\",\r\n    \"stateOfDress\": \"Immaculate, every detail corrected, makeup freshly applied with subtle enhancement\",\r\n    \"exposedBodyParts\": \"Face, hands, neck\",\r\n    \"clothingStateOfDress\": \"Clothed\",\r\n    \"hairStyle\": \"Dark brown armpit-length, brushed smooth and falling freely, styled carefully\",\r\n    \"posture\": \"Walking with purposeful stride toward friends, shoulders back, hips swaying slightly\",\r\n    \"semenOnBodyLocation\": \"None\",\r\n    \"bodyPosition\": \"Walking\",\r\n    \"nextActionsAccordingToPersonality\": [\r\n      \"Slide onto bench between Daphne and Tracey\",\r\n      \"Apologize for tardiness with plausible excuse\",\r\n      \"Share conspiratorial smile remembering earlier\"\r\n    ]\r\n  }\r\n}\r\n```\r\n</examplesGoodReplies>\r\n\r\n<important_reminders>\r\n- Before generating the new scene tracker, always consider the recent messages to ensure all changes are accurately represented.\r\n- You can only describe characters you know exist and are or may be in the scene.\r\n- Your primary objective is to ensure clarity, consistency, providing complete details even when specifics are not explicitly stated.\r\n- Note that the player ({{user}}) will always use first-person pronouns.\r\n- Your response must ONLY contain the Json representing the scene tracker.\r\n- Prefer shorter phrases and description, prefer keywords to long description.\r\n- Make sure to AVOID INCLUDING any characters that ARE NOT in the scene anymore.\r\n</important_reminders>\r\n</task>\n",
                                }
                            },
                            new PromptContextFormatElement
                            {
                                Tag = PromptContextFormatTag.World,
                                Name = "World",
                                Enabled = true,
                                Options = new PromptContextFormatElementOptions
                                {
                                    Format = "{{item_header}}\r\n{{item_description}}",
                                }
                            },
                            new PromptContextFormatElement
